class Vector:
    def __init__(self, x, y):
        self.x = x
        self.y = y

    def __add__(self, other):
        if isinstance(other, Vector):
            return Vector(self.x + other.x, self.y + other.y)
        return NotImplemented

    def __mul__(self, scalar):
        return Vector(self.x * scalar, self.y * scalar)

    def __rmul__(self, scalar):
        return self.__mul__(scalar)

    def __eq__(self, other):
        return isinstance(other, Vector) and self.x == other.x and self.y == other.y

    def __abs__(self):
        return (self.x ** 2 + self.y ** 2) ** 0.5

    def __repr__(self):
        return f"Vector({self.x}, {self.y})"

v1 = Vector(1, 2)
v2 = Vector(3, 4)
print(v1 + v2)          # Vector(4, 6)
print(3 * v1)           # Vector(3, 6) — uses __rmul__
print(abs(v2))          # 5.0
print(v1 == Vector(1, 2))  # True

# Augmented assignment for mutable vs immutable
n = 10
id_before = id(n)
n += 1
print(id(n) == id_before)  # False: new int object created

lst = [1, 2]
id_before = id(lst)
lst += [3, 4]              # calls __iadd__ — modifies in place
print(id(lst) == id_before)  # True: same list object
